// generate-schedule.js
// Builds data/schedule.json for a season from ESPN's public scoreboard API.
// The 2025 file was generated by a one-off that never got committed; this
// script makes regeneration a yearly re-run instead of a rebuild.
//
// Usage: node scripts/generate-schedule.js [season]   (default: 2026)
//
// Output schema matches the app's ScheduleService expectations exactly
// (same shape as the 2025 file): espn_event_id, week, date, home/away
// {team,name}, venue {name,city,state}, status.

const fs = require('fs').promises;
const path = require('path');

const delay = ms => new Promise(resolve => setTimeout(resolve, ms));

// ESPN abbreviations that differ from the Sleeper-style ones the app uses.
const TEAM_ABBR_FIX = {
  WSH: 'WAS',
};

function fixAbbr(abbr) {
  return TEAM_ABBR_FIX[abbr] || abbr;
}

async function fetchWeek(season, week) {
  const url = `https://site.api.espn.com/apis/site/v2/sports/football/nfl/scoreboard?seasontype=2&week=${week}&dates=${season}`;
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`ESPN API error for week ${week}: ${response.status}`);
  }
  const data = await response.json();
  return (data.events || []).map(event => {
    const comp = (event.competitions || [])[0] || {};
    const competitors = comp.competitors || [];
    const home = competitors.find(c => c.homeAway === 'home') || {};
    const away = competitors.find(c => c.homeAway === 'away') || {};
    const venue = comp.venue || {};
    const address = venue.address || {};
    return {
      espn_event_id: String(event.id),
      week,
      date: new Date(event.date).toISOString(),
      home: {
        team: fixAbbr(home.team ? home.team.abbreviation : '?'),
        name: home.team ? home.team.displayName : '?',
      },
      away: {
        team: fixAbbr(away.team ? away.team.abbreviation : '?'),
        name: away.team ? away.team.displayName : '?',
      },
      venue: {
        name: venue.fullName || 'TBD',
        city: address.city || '',
        state: address.state || '',
      },
      status: 'scheduled',
    };
  });
}

function validate(games) {
  const problems = [];

  if (games.length !== 272) {
    problems.push(`expected 272 games, got ${games.length}`);
  }

  // Every team must appear exactly 17 times.
  const appearances = {};
  for (const game of games) {
    appearances[game.home.team] = (appearances[game.home.team] || 0) + 1;
    appearances[game.away.team] = (appearances[game.away.team] || 0) + 1;
  }
  const teams = Object.keys(appearances).sort();
  if (teams.length !== 32) {
    problems.push(`expected 32 teams, got ${teams.length}: ${teams.join(',')}`);
  }
  for (const [team, count] of Object.entries(appearances)) {
    if (count !== 17) {
      problems.push(`${team} appears ${count} times (expected 17)`);
    }
  }

  // Byes per week (weeks where fewer than 32 teams play).
  const byes = {};
  for (let week = 1; week <= 18; week++) {
    const playing = new Set();
    for (const game of games.filter(g => g.week === week)) {
      playing.add(game.home.team);
      playing.add(game.away.team);
    }
    const off = teams.filter(t => !playing.has(t));
    if (off.length > 0) byes[week] = off.sort();
  }

  return { problems, byes, teams };
}

async function main() {
  const season = parseInt(process.argv[2] || '2026', 10);
  console.log(`Generating ${season} schedule from ESPN...`);

  let games = [];
  for (let week = 1; week <= 18; week++) {
    const weekGames = await fetchWeek(season, week);
    console.log(`  week ${week}: ${weekGames.length} games`);
    games = games.concat(weekGames);
    await delay(300);
  }

  games.sort((a, b) => a.week - b.week || a.date.localeCompare(b.date));

  const { problems, byes } = validate(games);
  console.log('\nBye weeks:');
  for (const [week, teams] of Object.entries(byes)) {
    console.log(`  week ${week}: ${teams.join(', ')}`);
  }
  if (problems.length > 0) {
    console.error('\nVALIDATION FAILED:');
    problems.forEach(p => console.error(`  - ${p}`));
    process.exit(1);
  }
  console.log('\nValidation passed: 272 games, 32 teams x 17 appearances.');

  const output = {
    version: `${season}.1`,
    lastUpdated: new Date().toISOString().slice(0, 10),
    season,
    totalGames: games.length,
    games,
  };

  const outPath = path.join(__dirname, '..', 'data', 'schedule.json');
  await fs.writeFile(outPath, JSON.stringify(output, null, 2));
  console.log(`Wrote ${outPath}`);
}

main().catch(error => {
  console.error('Schedule generation failed:', error.message);
  process.exit(1);
});
